-- destroy object
function LxUnity.DestroyObject(obj)
    if LxUnity.IsValidObject(obj) and LxUnity.IsValidObject(obj.gameObject) then
        LxUnity.GameObject.Destroy(obj)
    end
end
-- destroy gameobject
function LxUnity.Destroy(trans)
    if LxUnity.IsValidObject(trans) and LxUnity.IsValidObject(trans.gameObject) then
        LxUnity.GameObject.Destroy(trans.gameObject)
    end
end
-- destroy all child gameobject
function LxUnity.DestroyChild(trans)
    if (not trans) then
        return
    end
    local num = trans.childCount
    if num > 0 then
        local child = nil
        -- reverse for
        for i = num,1,-1 do
            child = trans:GetChild(i-1)
            LxUnity.Destroy(child)
        end
    end
end
-- destroy gameobject immediate
function LxUnity.DestroyImmediate(obj)
    if LxUnity.IsValidObject(obj) then
        LxUnity.GameObject.DestroyImmediate(obj.gameObject)
    end
end
-- destroy all child gameobject immediate
function LxUnity.DestroyChildImmediate(trans)
    local num = trans.childCount
    if num > 0 then
        local child = nil
        -- reverse for
        for i = num,1,-1 do
            local child = trans:GetChild(i-1)
            LxUnity.DestroyImmediate(child.gameObject)
        end
    end
end
