-- Instantiate gameobject
function LxUnity.InstantObject(obj)
    local clone = LxUnity.GameObject.Instantiate(obj)
    clone.name = obj.name
    return clone
end
-- new gameobject
function LxUnity.NewObject(name, parentTrans)
    local newObj = LxUnity.GameObject.New()
    local newTrans = newObj.transform
    if parentTrans then
        LxUnity.SetParentTrans(newTrans, parentTrans)
    end
    newObj.name = name
    return newTrans
end
function LxUnity.SetParentTrans(trans, parentTrans)
    if (parentTrans) then
        trans:SetParent(parentTrans, false)
    end
    trans.position = Vector3.zero
    trans.localScale = Vector3.one
    trans.localPosition = Vector3.zero
    trans.localRotation = Quaternion.identity
end
