-- show all child gameobject true/false
function LxUnity.ShowChildObject(trans, bShow)
    local childCnt = trans.childCount
    if (childCnt > 0) then
        local item
        for i = 0, childCnt - 1 do
            item = trans:GetChild(i)
            item.gameObject:SetActive(bShow)
        end
