function LxUnity.UpdateChildLayer(trans, layer, isSmartUpdate)
    if CS.IsNullObject(trans) then
        return nil
    end
    if (isSmartUpdate == nil) then
        isSmartUpdate = true
    end
    local updateNodes = nil
    local go = trans.gameObject
    if (isSmartUpdate and trans.childCount > 0) then
        if (trans:GetChild(0).gameObject.layer == layer) then
            return updateNodes
        end
    end
    updateNodes = {}

    local i
    local childs = go:GetComponentsInChildren(typeofTransform, true)
    for i = 0, childs.Length - 1 do
        if (childs[i].gameObject.layer ~= layer) then
            childs[i].gameObject.layer = layer
            table.insert(updateNodes, childs[i])
        end
    end
    return updateNodes
end

function LxUnity.UpdateNodesLayer(nodes, layer)
    if not nodes then
        return
    end

    local i
    local cnt = #nodes
    for i = 1, cnt do
        local trans = nodes[i]
        if (CS.IsValidObject(trans) and CS.IsValidObject(trans.gameObject) and trans.gameObject.layer ~= layer) then
            trans.gameObject.layer = layer
        end
    end
end

