function LxUnity.FindSceneRootTrans(name)
    local uSceneObj = LxUnity.GetSceneAt(0)
    local rootObjList = uSceneObj:GetRootGameObjects()
    local cnt, i
    cnt = rootObjList.Length
    local obj = nil
    for i = 1, cnt do
        obj = rootObjList[i - 1]
        if (obj.name == name) then
            return obj.transform
        end
    end
    return nil
end

