local _runtimeWebGL = URuntimePlatform.WebGLPlayer
local platform = UApplication.platform
local _isWebGL
function LxUnity.IsWebGL(isOnlyPlatform)
    if _isWebGL == nil then
        _isWebGL = platform == _runtimeWebGL
    end

    --判断是否仅判断平台，默认平台和数据一起判断
    if not isOnlyPlatform then
        if LGameSettings.isWebGL then
            return true
        end
    end

    return _isWebGL
end

