-----------------------------------------------------------------
function LxUnity.NumberTo(from,to,duration,callfunc)
    return YXTweenUtil.NumberTo(from,to,duration,callfunc)
end

function LxUnity.TweenFloat(from,to,duration,callfunc)
    local delegate = YXTweeningCore.DOSetter_float(callfunc)
    local tween = YXTweeningDoTween.To(delegate, from, to, duration)
    return tween
end

function LxUnity.TweenInt(from,to,duration,callfunc)
    local setter = YXTweeningCore.DOSetter_int(callfunc)
    local getter = YXTweeningCore.DOGetter_int(function()
        return from
    end)

    local tween = YXTweeningDoTween.To(getter, setter, to, duration)
    return tween
end

function LxUnity.TweenMove(object,toPos,duration,funCallBack)
    local dtSequence = YXTweeningDoTween.Sequence()
    local moveTween =object.transform:DOMove(toPos,duration,false)
    moveTween:SetEase(YXTweeningEase.Linear)
    moveTween:OnComplete(funCallBack)
    dtSequence:Append(moveTween)
    dtSequence:PlayForward()

    return dtSequence
end

function LxUnity.TweenSequenceIns()
    return YXTweeningDoTween.Sequence()
end


