function LxUnity.DecodeCryptKeyword(bytes, cryptKey, bCheckMd5, bDecode)
    return YXUtility.DecodeCryptKeyword(bytes, cryptKey, bCheckMd5, bDecode, nil)
end

------------------------------------------------------------------
--- 摇一摇
--- funcShakeEnd(int ret), ret=0=摇一摇触发 / ret=-2=超时
--- timeout = 超时秒数
--- factor = 摇一摇三维敏感度
function LxUnity.SetDeviceShake(funcShakeEnd, timeout, factor)
    timeout = timeout or 5.0
    factor = factor or 1.9
    YXDeviceShake.SetShakeShake(funcShakeEnd, timeout, factor)
end

--- FPS采样
--- func(int fpsAverage, int sampleCnt, int useTime) | 采样数量已满回调 或 主动调用EnableFps(nil)回调
--- fpsAverage=平均FPS, sampleCnt=实际采样数量, useTime=采样总时间
--- sampleCnt = 期望采样数量
--- fpsInterval = 采样频率（秒）
function LxUnity.EnableFps(func, sampleCnt, fpsInterval)
    sampleCnt = sampleCnt or 8
    fpsInterval = fpsInterval or 0.3
    YXDeviceFps.EnableFps(func, sampleCnt, fpsInterval)
end

function LxUnity.CallCsFun(type, param, callBack)
    if LxUnity.GameUtil then
        LxUnity.GameUtil.CallCsFun(type, param, callBack)
    end
end

function LxUnity.GetCsValue(type, subType)
    if LxUnity.GameUtil then
        return LxUnity.GameUtil.GetCsValue(type, subType or 0)
    end
end

